"""JavaScript body for the animated triangle anatomy scene."""

BODY = '/* cạnh nối tiếp: B→C (a), C→A (b), A→B (c) */\nvar ED=[[VB,VC],[VC,VA],[VA,VB]];\nfor(var i=0;i<3;i++){\n  var e=EZ(CL(P*3-i*0.9));\n  if(e<=0)continue;\n  var p1=ED[i][0], p2=ED[i][1];\n  ctx.strokeStyle="#e8e8ea";ctx.lineWidth=3;\n  ctx.beginPath();ctx.moveTo(p1[0],p1[1]);\n  ctx.lineTo(p1[0]+(p2[0]-p1[0])*e,p1[1]+(p2[1]-p1[1])*e);\n  ctx.stroke();\n}\nvar gx=(VA[0]+VB[0]+VC[0])/3, gy=(VA[1]+VB[1]+VC[1])/3;\n/* ── cung góc + nhãn góc tại 3 đỉnh ── */\nvar aE=CL(P*3-1.9);\nif(aE>0){\n  var VS=[VA,VB,VC];\n  ctx.font=\'400 30px Segoe UI, sans-serif\';\n  for(var i=0;i<3;i++){\n    var v=VS[i], o1=VS[(i+1)%3], o2=VS[(i+2)%3];\n    var a1=Math.atan2(o1[1]-v[1],o1[0]-v[0]);\n    var a2=Math.atan2(o2[1]-v[1],o2[0]-v[0]);\n    var d=a2-a1;\n    while(d>Math.PI)d-=Math.PI*2;\n    while(d<-Math.PI)d+=Math.PI*2;\n    ctx.globalAlpha=aE;\n    ctx.strokeStyle="rgba(232,232,234,0.45)";ctx.lineWidth=2;\n    ctx.beginPath();ctx.arc(v[0],v[1],__ARC__,a1,a1+d*EZ(aE),d<0);ctx.stroke();\n    var bis=a1+d/2;\n    ctx.fillStyle="#9a9aa0";\n    /* đỉnh A: né đường cao nét đứt (x=Ax) */\n    var lox=(i===0&&HL)?-36:0;\n    ctx.fillText(ANG[i],v[0]+Math.cos(bis)*__ALR__+lox,v[1]+Math.sin(bis)*__ALR__);\n    ctx.globalAlpha=1;\n  }\n  /* nhãn cạnh giữa mỗi cạnh, đẩy ra ngoài khỏi trọng tâm */\n  for(var i=0;i<3;i++){\n    var p1=ED[i][0], p2=ED[i][1];\n    var mx=(p1[0]+p2[0])/2, my=(p1[1]+p2[1])/2;\n    var dx=mx-gx, dy=my-gy;\n    var dl=Math.sqrt(dx*dx+dy*dy)||1;\n    ctx.globalAlpha=aE;ctx.fillStyle="#9a9aa0";\n    ctx.fillText(SID[i],mx+dx/dl*__SPU__,my+dy/dl*__SPU__);\n    ctx.globalAlpha=1;\n  }\n}\n/* ── đường cao nét đứt + vuông góc + nhãn h ── */\nif(HL){\n  var e4=EZ(CL(P*3-2));\n  if(e4>0){\n    ctx.strokeStyle="rgba(232,232,234,0.35)";ctx.lineWidth=2;\n    ctx.setLineDash([8,8]);\n    /* idle: nét đứt trôi dọc đường cao */\n    ctx.lineDashOffset=-time*8;\n    ctx.beginPath();ctx.moveTo(Ax,y0);ctx.lineTo(Ax,y0+__TH__*e4);ctx.stroke();\n    ctx.setLineDash([]);ctx.lineDashOffset=0;\n    /* reveal muộn ~65% step theo P2 */\n    var m4=CL(P2*4-2.6);\n    if(m4>0){\n      ctx.globalAlpha=m4;\n      var s=16;\n      ctx.strokeStyle="rgba(232,232,234,0.45)";ctx.lineWidth=2;\n      ctx.beginPath();ctx.moveTo(Ax-s,byv);ctx.lineTo(Ax-s,byv-s);\n      ctx.lineTo(Ax,byv-s);ctx.stroke();\n      ctx.font=\'400 30px Segoe UI, sans-serif\';ctx.fillStyle="#9a9aa0";\n      ctx.fillText(\'h\',Ax+28,y0+__HY__);\n      ctx.globalAlpha=1;\n    }\n  }\n}\n/* ── công thức: vế phải sau dấu = tô vàng (accent) — reveal muộn\n   ~giữa step theo P2 ── */\nvar fE=CL(P2*3-1.5);\nif(F&&fE>0){\n  ctx.globalAlpha=fE;\n  ctx.font=\'400 34px Segoe UI, sans-serif\';\n  var fy=byv+84;\n  var ix=F.indexOf(\'=\');\n  if(ix>=0){\n    var LP=F.substring(0,ix+1), RP=F.substring(ix+1);\n    var wl=ctx.measureText(LP).width, wr=ctx.measureText(RP).width;\n    var sx=W/2-(wl+wr)/2;\n    ctx.textAlign=\'left\';\n    ctx.fillStyle="#e8e8ea";ctx.fillText(LP,sx,fy);\n    /* idle: accent vàng thở nhẹ bằng shadowBlur */\n    ctx.shadowColor=\'rgba(250,204,21,0.4)\';\n    ctx.shadowBlur=9+6*Math.sin(time*1.6);\n    ctx.fillStyle="#facc15";ctx.fillText(RP,sx+wl,fy);\n    ctx.shadowBlur=0;\n    ctx.textAlign=\'center\';\n  }else{\n    ctx.fillStyle="#e8e8ea";ctx.fillText(F,W/2,fy);\n  }\n  ctx.globalAlpha=1;\n}\nctx.restore();'
